//Matriks görüntüsü için değişen ekran boyutları alınıyor. Ona göre güncelleme yapılıyor
window.addEventListener('resize', () => {
    canvas.width = window.innerWidth;
    canvas.height = window.innerHeight;

    // Yeniden boyutlandırma durumunda container'ın konumunu tekrar al
    containerRect = container.getBoundingClientRect();
});


function draw() {
    ctx.fillStyle = 'rgba(255, 255, 255, 0.05)';
    ctx.fillRect(0, 0, canvas.width, canvas.height);

    ctx.fillStyle = '#0F0';
    ctx.font = fontSize + 'px monospace';

    drops.forEach((y, x) => {
        const text = Math.random() > 0.5 ? '1' : '0';
        const posX = x * fontSize;
        const posY = y * fontSize;

        // Eğer sayıların çizileceği konum container alanının içinde ise çizme
        if (
            posX >= containerRect.left &&
            posX <= containerRect.right &&
            posY >= containerRect.top &&
            posY <= containerRect.bottom
        ) {
            drops[x]++;
            return;
        }

        ctx.fillText(text, posX, posY);

        if (posY > canvas.height && Math.random() > 0.975) {
            drops[x] = 0;
        } else {
            drops[x]++;
        }
    });

    container.backgroundImage=ctx;
}

// baslaBitirRow ögelerini belirli bir sıraya göre düzenleyen fonksiyon
function sortToolboxItems(toolboxInfo,window) {
    const order = [toolboxInfo+"-item1", toolboxInfo+"-item2", toolboxInfo+"-item3", toolboxInfo+"-item4", toolboxInfo+"-item5"];
    
    const items = Array.from(window.children);
    items.sort((a, b) => order.indexOf(a.id) - order.indexOf(b.id));

    items.forEach(item => window.appendChild(item)); // Sıralanmış ögeleri yeniden ekle
}

